### packages/runtime/src/renderer/AppContainer.tsx (새 파일)
```typescript
import { useEffect, useState } from 'react';
import { fetchApp } from '../communication/apiClient';
import { useRuntimeStore } from '../stores/runtimeStore';
import { ShellRenderer } from './ShellRenderer';
import { FormContainer } from './FormContainer'; // 기존 컴포넌트

interface Props {
  projectId?: string;
  formId?: string;
}

export function AppContainer({ projectId, formId }: Props) {
  const { shellDef, setShellDef, currentFormDef, setFormDef } = useRuntimeStore();

  useEffect(() => {
    if (projectId) {
      fetchApp(projectId, formId).then(({ shell, startForm }) => {
        setShellDef(shell);
        setFormDef(startForm);
      });
    }
  }, [projectId]);

  if (shellDef) return <ShellRenderer shell={shellDef} />;
  return <FormContainer />; // 기존 방식
}
```

